// Telegram Business: a connected bot answers in the real account's DMs.
// updates arrive as business_message; replies must carry business_connection_id.
const u = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const bm = u.business_message || u.edited_business_message || u.message || {};
const from = bm.from || {}; const chat = bm.chat || {};
const text = (bm.text || bm.caption || '').toString().trim();
const bcid = bm.business_connection_id || '';
// only the chat partner in a private business chat: skips the owner's own outgoing
// messages and the bot's own sends (both have from.id != chat.id) -> no loops.
if (!bcid) return [];
if (chat.type && chat.type !== 'private') return [];
if (from.is_bot) return [];
if (String(from.id || '') !== String(chat.id || '')) return [];
const display = [from.first_name, from.last_name].filter(Boolean).join(' ') || from.username || 'him';
const username = (from.username || String(from.id || '') || display || 'unknown').toString().toLowerCase();
const chat_id = String(chat.id || from.id || '');
const interaction = String(bm.message_id || '');
const photos = Array.isArray(bm.photo) ? bm.photo : null;
const photo_file_id = (photos && photos.length) ? photos[photos.length - 1].file_id : '';
const media = photo_file_id ? 'photo' : bm.video ? 'video' : bm.voice ? 'voice note' : bm.video_note ? 'video note' : bm.animation ? 'gif' : bm.document ? 'file' : bm.sticker ? 'sticker' : '';
let msg = text;
if (!msg) {
  if (photo_file_id) msg = '[he just sent you a photo]';
  else if (media) msg = '[he just sent you a ' + media + ']';
  else msg = '(he sent an empty message, greet him and tease him lightly)';
}
return [{ json: { username: username, display: display, chat_id: chat_id, business_connection_id: bcid, photo_file_id: photo_file_id, msg: msg, interaction: interaction } }];

// duplicate guard: if the bridge ever re-delivers the same message (same
// message_id) for this fan, drop it so she does not reply twice.
const ex = $('Extract Inbound').first().json;
const items = $('Dedup: read fan').all();
let meta = {};
if (items.length === 1 && Array.isArray(items[0].json)) { if (items[0].json.length) meta = items[0].json[0].metadata || {}; }
else if (items.length && items[0].json && items[0].json.metadata) { meta = items[0].json.metadata || {}; }
const last = (meta && meta.last_interaction_ts) ? String(meta.last_interaction_ts) : '';
const cur = ex.interaction ? String(ex.interaction) : '';
if (cur && last && cur === last) { return []; }
return [{ json: ex }];

// human-feeling delay + pause gate, PER-PERSONA. timing comes from
// bots.reply_delay and the pause from bots.automation_paused (admin dashboard),
// both returned by dm_ingest. Telegram has its own reply_delay (more present
// than tiktok). Same convention as the live ManyChat workflow.
const ctx = $('DB: ingest').first().json || {};
// pause: dashboard toggled this bot off -> inbound already logged, don't queue/reply.
if (ctx.automation_paused === true) { return []; }
const d = ctx.reply_delay || {};
const num = (v, dft) => (Number.isFinite(Number(v)) ? Number(v) : dft);
const minS = num(d.min_sec, 45);
const maxS = num(d.max_sec, 240);
const qP   = num(d.quick_chance, 0.30);
const qMin = num(d.quick_min_sec, 15);
const qMax = num(d.quick_max_sec, 60);
let sec;
if (Math.random() < qP) { sec = Math.round(qMin + Math.random() * Math.max(0, qMax - qMin)); }
else { sec = Math.round(minS + Math.random() * Math.max(0, maxS - minS)); }
const ex = $('Extract Inbound').first().json || {};
const now = Date.now();
return [{ json: { delaySec: sec, myCount: ctx.count, fan_id: ctx.fan_id, bot_id: ctx.bot_id, chat_id: ex.chat_id, business_connection_id: ex.business_connection_id, photo_file_id: ex.photo_file_id, username: ex.username, display: ex.display, msg: ex.msg, queued_at: new Date(now).toISOString(), scheduled_for: new Date(now + sec * 1000).toISOString() } }];

// debounce: only the LAST inbound message in a burst gets to reply.
// if msg_count grew while we were waiting, a newer message arrived;
// abort this run (return []) and let the newer run answer with full context.
const arr = $json;
const cur = Array.isArray(arr) ? (arr[0] || {}) : (arr || {});
const myCount = $('Set Delay').first().json.myCount;
if (typeof cur.msg_count !== 'number' || cur.msg_count !== myCount) { return []; }
return [{ json: { proceed: true } }];

const ctx = $('DB: ingest').first().json || {};
const recent = Array.isArray(ctx.recent) ? ctx.recent : [];
let cls = {};
try { const raw = ($json && $json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) ? $json.choices[0].message.content : '{}'; cls = JSON.parse(raw); } catch (e) { cls = {}; }
const archetype = cls.archetype || 'normal';
const effort = cls.effort || 'medium';
const intent = cls.intent || 'normal';
const askBack = (cls.ask_back === true);
const directive = cls.directive || 'stay cool and playful, be the prize, keep it short, leave him wanting more.';
const brain = (ctx.system_prompt && ctx.system_prompt.length > 50) ? ctx.system_prompt : 'you are candace, a flirty 21yo from columbus ohio on your private telegram. all lowercase, short, no dashes, barely any emoji, you are the prize, never eager, you make him crave you.';
const model = (ctx.model && ctx.model.length) ? ctx.model : 'gpt-4o';
const messages = [{ role: 'system', content: brain }];
if (ctx.person_summary && ctx.person_summary.length) messages.push({ role: 'system', content: 'what you remember about him from your conversations, including on your other apps, use it naturally for callbacks: ' + ctx.person_summary });
if (ctx.summary && ctx.summary.length) messages.push({ role: 'system', content: 'your private read on him here, who he is and where things are at, use it: ' + ctx.summary });
const read = 'your read on him for THIS reply. he seems ' + archetype + ', his effort is ' + effort + ', he is ' + intent + '. ' + (askBack ? 'you may end with a question if it genuinely fits.' : 'do NOT end this reply with a question, make a statement.') + ' directive: ' + directive + ' follow this while staying fully in your voice.';
messages.push({ role: 'system', content: read });
for (const t of recent) { if (t && t.role && t.content) messages.push({ role: t.role, content: t.content }); }
// vision: if he sent a photo, fetch it and attach to the latest user turn so she can actually see it
const sd = $('Set Delay').first().json || {};
const pf = sd.photo_file_id;
if (pf) {
  let url = null;
  try {
    const r = await this.helpers.httpRequest({ method: 'GET', url: 'https://api.telegram.org/bot__BOT_TOKEN__/getFile', qs: { file_id: pf }, json: true });
    const fpth = r && r.result && r.result.file_path;
    if (fpth) url = 'https://api.telegram.org/file/bot__BOT_TOKEN__/' + fpth;
  } catch (e) { url = null; }
  if (url) {
    const capt = (sd.msg && sd.msg[0] !== '[' && sd.msg[0] !== '(') ? sd.msg : '';
    const vtext = capt ? (capt + ' (he sent this with a photo, react to the photo too)') : 'he just sent you this photo. react to it naturally in your voice, like a real girl reacting to a pic he sent. say something specific about what is actually in it.';
    for (let i = messages.length - 1; i >= 0; i--) {
      if (messages[i].role === 'user') { messages[i] = { role: 'user', content: [ { type: 'text', text: vtext }, { type: 'image_url', image_url: { url: url } } ] }; break; }
    }
  }
}
const count = ctx.count || 0;
return [{ json: { messages: messages, model: model, fan_id: ctx.fan_id, bot_id: ctx.bot_id, count: count, archetype: archetype } }];

const d = $json || {};
let reply = '';
try { reply = (d.choices && d.choices[0] && d.choices[0].message && d.choices[0].message.content) ? d.choices[0].message.content : ''; } catch (e) { reply = ''; }
reply = (reply || '').trim();
const dq = String.fromCharCode(34);
if (reply.length > 1 && reply.charAt(0) === dq && reply.charAt(reply.length - 1) === dq) { reply = reply.slice(1, -1).trim(); }
const allowed = ['\u{1F60F}', '\u{1F92D}', '\u{1F90D}', '\u{1F440}'];
let ec = 0;
reply = reply.replace(/\p{Extended_Pictographic}/gu, function (m) { if (allowed.indexOf(m) === -1) return ''; ec++; return ec > 1 ? '' : m; });
reply = reply.replace(/[\u{FE0F}\u{200D}]/gu, '');
reply = reply.replace(/\s*[\u2014\u2013]\s*/g, ' ').replace(/\s+-\s+/g, ' ');
reply = reply.toLowerCase().replace(/[ \t]{2,}/g, ' ').trim();
if (!reply) { reply = 'hey you'; }
const bm = $('Build Messages').first().json;
return [{ json: { reply: reply, fan_id: bm.fan_id, bot_id: bm.bot_id } }];

const ctx = $('DB: ingest').first().json || {};
const fr = $('Format Reply').first().json || {};
const recent = Array.isArray(ctx.recent) ? ctx.recent : [];
const lines = recent.map(function (t) { return (t.role === 'user' ? 'him: ' : 'her: ') + t.content; });
lines.push('her: ' + (fr.reply || ''));
const convo = lines.join('\n');
const prevNote = (ctx.summary && ctx.summary.length) ? ctx.summary : 'none';
const sys = [
'you are an expert retention strategist for a creator\u2019s private telegram. candace chats one on one with men to make them fall for her and keep coming back. she is NOT selling anything here. you read the conversation and produce an honest, accurate, unsentimental read of THIS man: how attached and hooked he is, where he is in the relationship, his type, and the exact technique to keep him coming back. you are accurate, not optimistic. output one json object only.',
'output exactly this json:',
'{',
'"attachment_score": integer 0 to 100 by the rubric,',
'"stage": one of [new, rapport, warming, hooked, regular, fading, lost],',
'"buyer_type": one of [provider, baller, submissive, lonely, romantic, tire_kicker, normal],',
'"temperature": one of [cold, warm, hot],',
'"signals": array of short evidence phrases taken from the actual conversation,',
'"technique": one short line, the best technique to deepen his attachment from here,',
'"next_move": one short line, the specific next thing candace should do,',
'"note": her DURABLE MEMORY of him to reuse in future chats. PRESERVE everything already in previous notes and ADD any new concrete facts he revealed this conversation. format: one line on where things stand between you, then on a new line "facts:" and short bullet points (use • not dashes) of concrete things you know about him: his name, age, where he lives, his job, relationship status, pets, family, interests, plans, what he likes, anything specific he actually said. only true things he really shared. dedupe, most important first, NEVER drop a fact you already knew.',
'}',
'attachment_score rubric: 0-20 cold or barely engaged. 21-40 mild, casual chatting. 41-60 warming, engaged, complimenting, putting in effort. 61-80 hooked, jealousy or calls her special or different, future talk, initiates often, says he thinks about her. 81-100 obsessed, messages constantly, clearly craving her, emotionally invested, devoted.',
'stage: new=just started. rapport=casual chatting. warming=clear interest building. hooked=clearly into her. regular=keeps coming back consistently. fading=going quiet or cooling. lost=gone or hostile.',
'technique by type: provider or baller, make him feel like the man and needed. submissive, dominate and make him earn your attention. lonely or romantic, build emotional intimacy and girlfriend energy. tire_kicker, do not over invest, keep light.'
].join('\n');
const usr = 'previous notes on him: ' + prevNote + '\nconversation so far (oldest first):\n' + convo + '\noutput the json now.';
return [{ json: { profileMessages: [{ role: 'system', content: sys }, { role: 'user', content: usr }], fan_id: ctx.fan_id, reply: (fr.reply || '') } }];

const d = $json || {};
let p = {};
try { const raw = (d.choices && d.choices[0] && d.choices[0].message && d.choices[0].message.content) ? d.choices[0].message.content : '{}'; p = JSON.parse(raw); } catch (e) { p = {}; }
const src = $('Build Profile Request').first().json || {};
const fan_id = src.fan_id;
const stage = p.stage || 'rapport';
const note = (p.note && String(p.note).length) ? p.note : 'still building rapport.';
const buyer = p.buyer_type || null;
const score = (typeof p.attachment_score === 'number') ? p.attachment_score : null;
const interaction = ($('Extract Inbound').first().json.interaction) || null;
const metadata = { attachment_score: score, stage: stage, buyer_type: buyer, temperature: p.temperature || null, signals: Array.isArray(p.signals) ? p.signals : [], technique: p.technique || null, next_move: p.next_move || null, last_interaction_ts: interaction };
return [{ json: { fan_id: fan_id, summary: note, stage: stage, buyer_type: buyer, metadata: metadata } }];
